import React from 'react'
import '../styles.css'
import styled from "styled-components";

const MealsContainer = ({meals}) => {
    // console.log(meals[0].title);
    return (

    <Wrapper>{meals.map(e => {
        // {console.log(e.id)}
        <div key={e.id}>{e.title}</div>
        })}
    </Wrapper>
    );
};

export default MealsContainer
